import React, { useEffect, useState } from 'react';
import SellerBadge from '../components/SellerBadge';
import { Link } from 'react-router-dom';
import axios from 'axios';

const Dashboard = () => {
  const [user, setUser] = useState({ email: '', isVerified: false });
  const [history, setHistory] = useState([]);
  const [myListings, setMyListings] = useState([]); // New state for listings

  useEffect(() => {
    // Retrieve the data we stored during the Login step
    const email = localStorage.getItem('userEmail');
    const isVerified = localStorage.getItem('isVerified') === 'true';
    const userId = localStorage.getItem('userId');
    
    setUser({ email, isVerified });

    const fetchData = async () => {
      try {
        // Fetch Purchase History
        const historyRes = await axios.get(`http://localhost:5000/api/transactions/history/${userId}`);
        setHistory(historyRes.data);

        // Fetch My Listings (The new part!)
        const listingsRes = await axios.get(`http://localhost:5000/api/items/user-listings/${userId}`);
        setMyListings(listingsRes.data);
      } catch (err) {
        console.error("Error fetching dashboard data", err);
      }
    };

    if (userId) fetchData();
  }, []);

  return (
    <div style={{ padding: '40px', fontFamily: 'Arial, sans-serif' }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <h1>
          Welcome, {user.email} 
          <SellerBadge isVerified={user.isVerified} />
        </h1>
      </header>

      <section style={{ marginTop: '30px', borderTop: '1px solid #eee', paddingTop: '20px' }}>
        <h3>Your Activity</h3>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
          <div style={{ padding: '20px', background: '#f9f9f9', borderRadius: '8px' }}>
            <h4>Your Active Listings</h4>
            {myListings.length > 0 ? (
              <ul style={{ listStyle: 'none', padding: 0 }}>
                {myListings.map((item) => (
                  <li key={item._id} style={{ marginBottom: '10px', padding: '5px', borderBottom: '1px solid #ddd' }}>
                    <strong>{item.title}</strong> - ${item.price}
                    <br /><small>{item.category}</small>
                  </li>
                ))}
              </ul>
            ) : (
              <p>You haven't listed any items yet.</p>
            )}
            
            <Link to="/create-listing">
              <button style={{ 
                background: '#1a1a1a', 
                color: 'white', 
                border: 'none', 
                padding: '10px', 
                borderRadius: '4px',
                cursor: 'pointer' 
              }}>
                + Create New Listing
              </button>
            </Link>
          </div>
          <div style={{ padding: '20px', background: '#f9f9f9', borderRadius: '8px' }}>
            <h4>Order History</h4>
            {history.length > 0 ? (
              <ul style={{ listStyle: 'none', padding: 0 }}>
                {history.map((tx) => (
                  <li key={tx._id} style={{ marginBottom: '10px', borderBottom: '1px solid #ddd' }}>
                    <strong>{tx.title}</strong> - ${tx.price} <br />
                    <small>Purchased on: {new Date(tx.purchaseDate).toLocaleDateString()}</small>
                  </li>
                ))}
              </ul>
            ) : (
              <p>No recent transactions found.</p>
            )}
          </div>
        </div>
      </section>
    </div>
  );
};

export default Dashboard;
